"""Runtime-конфигурация извлечения: строится из project-level extract payload, используется только при выполнении extract."""from __future__ import annotationsfrom dataclasses import dataclassfrom pathlib import Pathfrom typing import Anyfrom src.core.utils.hash import md5_string@dataclassclass ExtractConfig:    """Конфигурация извлечения на момент выполнения. Строится из group-based extract payload. Не путать с project-level schema/payload API."""    project_path: Path | str    """Провайдер -> { ключ поля из схемы -> значение }. Заполняется из нормализованного payload по реестру схем."""    provider_configs: dict[str, dict[str, Any]] | None = None    cache_path: Path | None = None    def __post_init__(self) -> None:        if self.provider_configs is None:            object.__setattr__(self, "provider_configs", {})    def get_provider_value(self, provider_code: str, key: str, default: Any = None) -> Any:        """Значение поля провайдера по ключу из схемы."""        cfg = (self.provider_configs or {}).get(provider_code) or {}        return cfg.get(key, default)    @property    def cache_dir(self) -> Path:        """Директория кэша извлечения: cache_path при заданном, иначе <project>/extract/."""        if self.cache_path is not None:            return self.cache_path        base = Path(self.project_path) if isinstance(self.project_path, str) else self.project_path        return base / "extract"    def to_canonical_string(self) -> str:        """Каноническая строка всех параметров (без путей) для создания хеша. Используется вместе с хешем файла для ключа кэша."""        parts: list[str] = []        pc = self.provider_configs or {}        for code in sorted(pc):            vals = pc[code]            for k in sorted(vals):                parts.append(f"providers.{code}.{k}={vals[k]!r}")        return "\n".join(parts)    def canonical_hash(self) -> str:        """Хеш канонической строки конфигурации (без путей)."""        return md5_string(self.to_canonical_string())